// ── Account helpers ──────────────────────────────────────────────

fn signer(address: Pubkey) -> Account {
    quasar_svm::token::create_keyed_system_account(&address, 10_000_000_000)
}

fn empty(address: Pubkey) -> Account {
    Account {
        address,
        lamports: 0,
        data: vec![],
        owner: quasar_svm::system_program::ID,
        executable: false,
    }
}

/// Create a pre-populated MultisigAccount account (program-owned).
fn state_account(
    address: Pubkey,
    creator: [u8; 32],
    threshold: u8,
    member_count: u8,
    members: [[u8; 32]; 32],
    voted: [u8; 32],
    approval_count: u8,
    rejection_count: u8,
    bump: u8,
) -> Account {
    let state = MultisigAccount {
        creator,
        threshold,
        member_count,
        members,
        voted,
        approval_count,
        rejection_count,
        bump,
    };
    Account {
        address,
        lamports: 2_000_000,
        data: wincode::serialize(&state).unwrap(),
        owner: crate::ID,
        executable: false,
    }
}

